const SidePanel = ({ open, onClose, tab, onTabChange, onDictClick }) => {
  if (!open) return null;
  const tabs = [
    { id: 'score', label: '역량 점수 기준',},
    { id: 'discover', label: '경험 발굴',},
    { id: 'dict', label: '역량 사전',},
  ];
  return (
    <div style={{ position: 'fixed', top: 0, right: 0, bottom: 0, width: '100%', maxWidth: 420, background: COLORS.white, borderLeft: `1px solid ${COLORS.border}`, boxShadow: '-8px 0 24px rgba(14, 39, 80,0.08)', zIndex: 50, display: 'flex', flexDirection: 'column' }}>
      <div style={{ padding: SPACING.base, borderBottom: `1px solid ${COLORS.border}`, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <p style={{ fontSize: FONT.size.md, fontWeight: FONT.weight.semibold, color: COLORS.accent, margin: 0 }}>참고 자료</p>
        <button onClick={onClose} style={{ background: 'transparent', border: 'none', cursor: 'pointer', color: COLORS.sub, padding: 4 }}></button>
      </div>
      <div style={{ display: 'flex', borderBottom: `1px solid ${COLORS.border}`, background: COLORS.bgAlt }}>
        {tabs.map(t => {
          const active = tab === t.id;
          const TabIcon = t.icon;
          return (
            <button key={t.id} onClick={() => onTabChange(t.id)}
              style={{ flex: 1, padding: `${SPACING.base}px ${SPACING.sm}px`, background: active ? COLORS.white : 'transparent', border: 'none', borderBottom: active ? `2px solid ${COLORS.accent}` : '2px solid transparent', color: active ? COLORS.accent : COLORS.sub, fontSize: FONT.size.sm, fontWeight: FONT.weight.semibold, cursor: 'pointer', display: 'inline-flex', alignItems: 'center', justifyContent: 'center', gap: 4 }}>
              <TabIcon size={12} /> {t.label}
            </button>
          );
        })}
      </div>
      <div style={{ flex: 1, overflowY: 'auto', padding: SPACING.md }}>
        {tab === 'score' && <ScorePanel />}
        {tab === 'discover' && <DiscoveryPanel />}
        {tab === 'dict' && <DictionaryPanel onPick={onDictClick} />}
      </div>
    </div>
  );
};

